+    #[test]
+    fn ball_cache_len_matches_quality_count() {
+        let mut fx = MetaballsFx::default();
+        let total = fx.params.balls.len();
+
+        fx.populate_ball_cache(0.0, FxQuality::Full);
+        assert_eq!(fx.ball_cache.len(), total);
+
